package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;

  @BeforeEach
  public void setUp() throws Exception {
    // Create a dummy JsonPrimitive with boolean true value
    JsonPrimitive truePrimitive = new JsonPrimitive(true);

    // Instantiate JsonTreeReader with a dummy JsonPrimitive via reflection
    jsonTreeReader = (JsonTreeReader) createInstance(JsonTreeReader.class);
    // Manually push the JsonPrimitive onto the stack
    pushStack(jsonTreeReader, truePrimitive);
  }

  @Test
  public void testNextBooleanTrue() throws Exception {
    // Set stackSize to 1 because we pushed one element
    setStackSize(jsonTreeReader, 1);
    // Set pathIndices and stackSize for path increment testing
    setPathIndices(jsonTreeReader, new int[32]);
    setStackSize(jsonTreeReader, 1);

    // Mock expect method to do nothing (bypass it)
    invokePrivateVoidMethod(jsonTreeReader, "expect", JsonToken.BOOLEAN);

    // Call nextBoolean and verify it returns true
    boolean result = jsonTreeReader.nextBoolean();

    assertTrue(result);

    // Verify that pathIndices[stackSize - 1] incremented by 1
    int[] pathIndices = getPathIndices(jsonTreeReader);
    assertEquals(1, pathIndices[0]);
  }

  @Test
  public void testNextBooleanFalse() throws Exception {
    // Prepare JsonPrimitive with false
    JsonPrimitive falsePrimitive = new JsonPrimitive(false);
    jsonTreeReader = (JsonTreeReader) createInstance(JsonTreeReader.class);
    pushStack(jsonTreeReader, falsePrimitive);
    setStackSize(jsonTreeReader, 1);
    setPathIndices(jsonTreeReader, new int[32]);

    // Bypass expect method
    invokePrivateVoidMethod(jsonTreeReader, "expect", JsonToken.BOOLEAN);

    boolean result = jsonTreeReader.nextBoolean();

    assertFalse(result);

    int[] pathIndices = getPathIndices(jsonTreeReader);
    assertEquals(1, pathIndices[0]);
  }

  @Test
  public void testNextBooleanStackSizeZero() throws Exception {
    // Prepare JsonPrimitive with true
    JsonPrimitive truePrimitive = new JsonPrimitive(true);
    jsonTreeReader = (JsonTreeReader) createInstance(JsonTreeReader.class);
    pushStack(jsonTreeReader, truePrimitive);
    // Set stackSize to 1 and then decrement to 0 after popStack call inside nextBoolean
    setStackSize(jsonTreeReader, 1);
    setPathIndices(jsonTreeReader, new int[32]);

    // Bypass expect method
    invokePrivateVoidMethod(jsonTreeReader, "expect", JsonToken.BOOLEAN);

    // Manually set stackSize to 1, but after popStack it will become 0 inside nextBoolean
    // So we simulate that by overriding popStack to remove the element and decrement stackSize
    // But since popStack is private, we rely on the real method behavior

    // Call nextBoolean
    boolean result = jsonTreeReader.nextBoolean();

    assertTrue(result);

    // After popStack, stackSize will be zero, so pathIndices should not increment
    int[] pathIndices = getPathIndices(jsonTreeReader);
    assertEquals(0, pathIndices[0]);
  }

  // Helper methods for reflection

  private static Object createInstance(Class<?> clazz) throws Exception {
    return clazz.getDeclaredConstructor(com.google.gson.JsonElement.class)
        .newInstance(new JsonPrimitive(true));
  }

  private static void pushStack(JsonTreeReader reader, Object element) throws Exception {
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(reader);
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int stackSize = stackSizeField.getInt(reader);
    stack[stackSize] = element;
    stackField.set(reader, stack);
    stackSizeField.setInt(reader, stackSize + 1);
  }

  private static void setStackSize(JsonTreeReader reader, int size) throws Exception {
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, size);
  }

  private static void setPathIndices(JsonTreeReader reader, int[] pathIndices) throws Exception {
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    pathIndicesField.set(reader, pathIndices);
  }

  private static int[] getPathIndices(JsonTreeReader reader) throws Exception {
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    return (int[]) pathIndicesField.get(reader);
  }

  private static void invokePrivateVoidMethod(Object obj, String methodName, Object... args) throws Exception {
    Class<?>[] argTypes = new Class<?>[args.length];
    for (int i = 0; i < args.length; i++) {
      argTypes[i] = args[i].getClass();
    }
    Method method = JsonTreeReader.class.getDeclaredMethod(methodName, argTypes);
    method.setAccessible(true);
    method.invoke(obj, args);
  }
}
